import React from 'react';
import logo from '../Assets/logo.png'; 
import facebookIcon from '../Assets/facebook.png'; 
import linkedinIcon from '../Assets/linkedin.png'; 
import instagramIcon from '../Assets/insta.png'; 
import twitterIcon from '../Assets/twitter.png'; 

const Footer = () => {
  return (
    <footer className="bg-white text-black py-4 border-t border-gray-300">
       <div className="container mx-auto flex justify-between items-start">
        <div className="flex items-center">
          {/* Check if the logo is being correctly referenced */}
          <img src={logo} alt="Logo" className="h-8 w-auto mr-2" onError={(e) => { e.target.onerror = null; e.target.src = 'fallback-logo.png'; }} />
          <span className="font-bold"></span>
        </div>
        <div className="flex-1 flex flex-col items-center border-l border-r border-gray-300 px-8">
          <h3 className="font-bold mb-2">Address</h3>
          <p>Vancouver, BC</p>
        </div>
        <div className="flex flex-col items-center border-l border-gray-300 pl-8">
          <h3 className="font-bold mb-2">Contacts</h3>
          <p>info@example.com</p>
          <p>(123) 456-7890</p>
          <div className="flex space-x-4 mt-2">
            <a href="https://facebook.com" className="flex items-center text-blue-500 hover:text-blue-700">
              <img src={facebookIcon} alt="Facebook" className="h-6 w-6 mr-1" />
            </a>
            <a href="https://linkedin.com" className="flex items-center text-blue-500 hover:text-blue-700">
              <img src={linkedinIcon} alt="LinkedIn" className="h-6 w-6 mr-1" />
            </a>
            <a href="https://instagram.com" className="flex items-center text-blue-500 hover:text-blue-700">
              <img src={instagramIcon} alt="Instagram" className="h-6 w-6 mr-1" />
            </a>
            <a href="https://twitter.com" className="flex items-center text-blue-500 hover:text-blue-700">
              <img src={twitterIcon} alt="Twitter" className="h-6 w-6 mr-1" />
            </a>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
